              label: 'Reliability & Retransmission',
              short: 'REL',
              description: 'Per §3.5.4 and §3.5.12: PSN-based reliability with ACK/NACK/SACK control packets and selective retransmission state machines.',
              longDescription: `Per §3.5.4 and §3.5.12, reliability uses cumulative progress + selective hole repair. Let PSN_base be highest contiguous packet received. ACK advances PSN_base, NACK identifies specific missing packets, and SACK bitmap marks non-contiguous packets above base. Retransmission set is exactly missing set M, not full window replay. Timeout fallback uses RTO with smoothed RTT and variance, while trimmed-header signals allow earlier repair. This minimizes redundant traffic under burst loss and preserves throughput.`,
              techDetails: [
                { label: 'Section Anchor', content: '§3.5.4 + §3.5.12 ACK/NACK/SACK semantics' },
                { label: 'Cumulative ACK', content: 'Advances base frontier: PSN_base <- max contiguous received PSN' },
                { label: 'SACK Bitmap Model', content: 'For offset i above base, bit_i=1 means received, bit_i=0 means missing; retransmit targets zero bits only' },
                { label: 'Repair Set', content: 'M = {psn | psn in window AND psn not cumulatively ACKed AND not SACK-marked}' },
                { label: 'RTO Model', content: 'RTO approximately SRTT + K*RTTVAR with K near 4; implementation may clamp min/max' },
                { label: 'Trim Fast Path', content: 'Trimmed payload + forwarded header enables early NACK emission before full timer expiry' },
                { label: 'Efficiency', content: 'Avoids go-back-N retransmit storms and reduces unnecessary bandwidth under random loss' },
              ],
              details: ['PSN_base frontier', 'M missing-set repair', 'SRTT/RTTVAR', 'Trim early-repair'],
