export function findNode(tree: UETNode, id: string): UETNode | null {
  if (tree.id === id) return tree;
  for (const child of tree.children || []) {
    const found = findNode(child, id);
    if (found) return found;
  }
  return null;
}

export function findPath(tree: UETNode, id: string, path: UETNode[] = []): UETNode[] | null {
  if (tree.id === id) return [...path, tree];
  for (const child of tree.children || []) {
    const found = findPath(child, id, [...path, tree]);
    if (found) return found;
  }
  return null;
}
